// -*- coding: utf-8 -*-
#include <iostream>
#include <unordered_map>
#include <string>
#include <cassert>

using namespace std;

class Trie {
public:
    void insert(const string& word) {
        node = trie;
        for (char ch : word) {
            node = node[ch];
        } node['$'] = ''; 
    }

    bool search(const string& word) {
        node = trie;
        for (char ch : word) {
            if (node.find(ch) == node.end()) {
                return false;
            }
            node = node[ch];
        }
        return node.find('$') != node.end();
    }
private:
    unordered_map<char, unordered_map<char, void*>> trie;
};

int main() {
    Trie trie;
    trie.insert('apple');
    trie.insert('banana');
    cout << (trie.search('apple') ? "True" : "False") << endl;
    cout << (trie.search('banana') ? "True" : "False") << endl;
    cout << (trie.search('orange') ? "True" : "False") << endl;
    return 0;
}
